teiHeader.xenoData:

{
"pipeline": "TEI-driven et AI-assisted workflow for Castello dell’anima",
"model": {
"primary": "Claude 3 Sonnet",
"fallback": "GPT-4.1",
"constraints": {
"historical_style": "XVII-century Italian",
"forbidden": [
"modernisms",
"anachronisms",
"semantic elaborations"
],
"tei_integrity": true
}
},
"operations": {
"remove_citation": { "code": "-CIT" },
"replace_citation": { "code": "+CIT'" },
"add_glossa_ai":   { "code": "+GLOSSA_AI" },
"reposition":      { "code": "RIC" }
},
"parameters": {
"seed_values": {
"-CIT": 1729,
"+CIT'": 1731,
"+GLOSSA_AI": 1733
},
"temperature": 0.2,
"top_p": 0.95,
"max_glossa_words": 35
},
"indicators": {
"clarity_score": "0–1 continuous",
"doctrinal_risk": ["low","medium","high"],
"cohesion_local": "referential chains delta pre/post",
"explanatory_impact": "I = 0.40*N + 0.35*A + 0.25*F"
},
"audit_trail": {
"required_fields": [
"locus_id", "operation", "seed",
"prompt_hash", "output_hash",
"reviewer", "esito", "notes"
],
"governance": "expert-in-the-loop"
},
"last_update": "2026-04-10"
}

revisionDesc.change:
Prime prove di
               annotazione interpretativa dei nodi dottrinali complessi tramite &lt;seg&gt;
               con valori multipli in @ana e verifica della compatibilità con la struttura TEI P5.
